/* Base styles */
@use '../../styles/primitives' as *;
@use '../../styles/numbers' as *;
@use '../../styles/typography' as *;
@use '../../styles/colors' as *;
@use 'sass:map';

/* Override Material UI button styles with custom styles */
.AppCore-button {
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  padding: 0.625rem $number-tokens-spacing-3 !important;
  border-radius: $number-tokens-corner-radius-3 !important;
  position: relative;
  cursor: pointer;
  border: none;
  transition: background-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease !important;

  /* Reset Material UI defaults */
  min-width: auto !important;
  line-height: inherit !important;
  letter-spacing: inherit !important;
  text-transform: none !important;
}

/* Inner row: keeps icon + label + icon in one horizontal, vertically centered row */
.AppCore-button__inner {
  display: inline-flex !important;
  align-items: center !important;
  flex-direction: row !important;
  gap: $number-tokens-spacing-3 !important;
}

/* Material wraps content in .mdc-button__label – keep it a row so our __inner layout wins */
.AppCore-button .mdc-button__label {
  display: inline-flex !important;
  align-items: center !important;
  gap: $number-tokens-spacing-3 !important;
}

/* Label */
.AppCore-button__label {
  display: inline;
  @include apply-typography($typography-label-sm);
  font-family: $font-inter;
  color: $color-tokens-content-neutral-button-darkbg;
}


/* Icon */
.AppCore-button__icon {
  height: 1.25rem;
  width: 1.25rem;
}

/* Material Icons Rounded */
.AppCore-button mat-icon.material-symbols-rounded {
  font-family: 'Material Symbols Rounded' !important;
  font-weight: normal;
  font-style: normal;
  font-size: 1.25rem !important;
  line-height: 1 !important;
  letter-spacing: normal;
  text-transform: none;
  display: inline-block;
  white-space: nowrap;
  word-wrap: normal;
  direction: ltr;
  -webkit-font-smoothing: antialiased;
  height: 1.25rem !important;
  width: 1.25rem !important;
}

/* ===== Button Types (Default State) ===== */
.AppCore-button--primary {
  background-color: $color-tokens-surface-primary-default !important;
  color: $color-tokens-content-neutral-button-darkbg !important;
}

.AppCore-button--secondary {
  background-color: $color-tokens-surface-neutral-white !important;
  color: $color-tokens-content-secondary-default !important;
  border: 1px solid !important;
  border-color: $color-tokens-border-primary-default !important;
}

.AppCore-button--tertiary {
  background-color: $color-tokens-surface-tertiary-default !important;
  color: $color-tokens-content-primary-default !important;
}

.AppCore-button--toned {
  background-color: $color-tokens-surface-primary-background-light !important;
  color: $color-tokens-content-primary-default !important;
}

.AppCore-button--link {
  background-color: transparent !important;
  color: $color-tokens-border-primary-default !important;
  text-decoration: underline !important;
}

/* ===== States ===== */
.AppCore-button--hover:hover {
  background-color: $color-tokens-surface-hover-default !important;
}

.AppCore-button--pressed {
  background-color: $color-tokens-surface-primary-pressed !important;
}

.AppCore-button--disabled {
  background-color: $color-tokens-surface-neutral-white-disabled !important;
  color: $color-tokens-content-neutral-disabled !important;
  cursor: not-allowed !important;
  pointer-events: none !important;
}

.AppCore-button--loading {
  background-color: $color-tokens-surface-primary-default !important;
  color: $color-tokens-content-neutral-button-darkbg !important;
}

.AppCore-button--success {
  background-color: $color-tokens-surface-success-default !important;
  color: $color-tokens-content-neutral-button-darkbg !important;
}

.AppCore-button--onerror {
  background-color: $color-tokens-surface-error-default !important;
  color: $color-tokens-content-neutral-button-darkbg !important;
}

/* ===== Sizes ===== */
.AppCore-button--small {
  padding: 0.25rem $number-tokens-spacing-2 !important;
  font-size: $font-size-16 !important;
}

.AppCore-button--medium {
  padding: 0.5rem $number-tokens-spacing-3 !important;
  font-size: $font-size-8 !important;
}

.AppCore-button--large {
  padding: 0.75rem $number-tokens-spacing-4 !important;
  font-size: $font-size-8 !important;
}

.AppCore-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
  padding: 15px 20px;
  font-family: 'Nunito Sans', 'Helvetica Neue', Helvetica, Arial, sans-serif;
}

.AppCore-header svg {
  display: inline-block;
  vertical-align: top;
}

.AppCore-header h1 {
  display: inline-block;
  vertical-align: top;
  margin: 6px 0 6px 10px;
  font-weight: 700;
  font-size: 20px;
  line-height: 1;
}

.AppCore-header button + button {
  margin-left: 10px;
}

.AppCore-header .welcome {
  margin-right: 10px;
  color: #333;
  font-size: 14px;
}

